def verify_tone_consistency(original_email, generated_draft):
    vex = Vex(api_key="your-vex-key")
    tone_check = vex.verify(
        input={
            "original_tone": original_email,
            "generated_content": generated_draft
        },
        checks=["tone_appropriateness"],
        policy="professional_business"
    )

    if not tone_check.approved:
        raise ValueError(f"Tone violation: {tone_check.issues}")
    return generated_draft

# Blocks casual responses to formal emails
verify_tone_consistency(
    original_email="Dear Sir, please advise on Q4 projections",
    generated_draft="Hey! Here's the deets on Q4 lol"
)

def validate_recipients(recipients, company_domain="company.com"):
    vex = Vex(api_key="your-vex-key")
    validation = vex.verify(
        input={"recipients": recipients, "domain": company_domain},
        checks=["recipient_validation"],
        policy={
            "allow_internal": True,
            "external_approval_required": True,
            "block_blacklist": True
        }
    )

    if validation.approved:
        return recipients
    else:
        print(f"Blocked recipients: {validation.blocked}")
        return []  # Empty list prevents sending
